import { useState, useEffect, useCallback } from 'react';
import api from '../services/api';
import useAuthStore from '../store/useAuthStore';
import { Users, Plus, Edit2, Trash2, Search, Download, Filter, X } from 'lucide-react';
import * as XLSX from 'xlsx';
import toast from 'react-hot-toast';

const TeachersPage = () => {
  const { user } = useAuthStore();
  const [teachers, setTeachers] = useState([]);
  const [departments, setDepartments] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDept, setSelectedDept] = useState('all');

  // Modal State
  const [modalOpen, setModalOpen] = useState(false);
  const [editingTeacher, setEditingTeacher] = useState(null);
  const [formData, setFormData] = useState({
    name: '',
    employeeId: '',
    email: '',
    phone: '',
    department: '',
    qualification: '',
    experience: 0,
    maxDailyPeriods: 4,
    maxWeeklyPeriods: 20,
    workingDays: ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'],
  });

  const fetchTeachers = useCallback(async () => {
    await Promise.resolve();
    setIsLoading(true);
    try {
      const [tRes, dRes] = await Promise.all([
        api.get(`/teachers?department=${selectedDept}&search=${encodeURIComponent(searchQuery)}`),
        api.get('/departments'),
      ]);
      setTeachers(tRes.data.data || []);
      setDepartments(dRes.data.data || []);
    } catch (error) {
      console.error('Error fetching teachers:', error);
      toast.error('Failed to load teachers');
    } finally {
      setIsLoading(false);
    }
  }, [selectedDept, searchQuery]);

  useEffect(() => {
    fetchTeachers();
  }, [fetchTeachers]);

  const handleOpenModal = (t = null) => {
    if (t) {
      setEditingTeacher(t);
      setFormData({
        name: t.name,
        employeeId: t.employeeId,
        email: t.email,
        phone: t.phone || '',
        department: t.department?._id || t.department || '',
        qualification: t.qualification || '',
        experience: t.experience || 0,
        maxDailyPeriods: t.maxDailyPeriods || 4,
        maxWeeklyPeriods: t.maxWeeklyPeriods || 20,
        workingDays: t.workingDays || ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'],
      });
    } else {
      setEditingTeacher(null);
      setFormData({
        name: '',
        employeeId: `EMP${Math.floor(1000 + Math.random() * 9000)}`,
        email: '',
        phone: '',
        department: departments[0]?._id || '',
        qualification: '',
        experience: 0,
        maxDailyPeriods: 4,
        maxWeeklyPeriods: 20,
        workingDays: ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'],
      });
    }
    setModalOpen(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingTeacher) {
        await api.put(`/teachers/${editingTeacher._id}`, formData);
        toast.success('Teacher updated successfully!');
      } else {
        await api.post('/teachers', formData);
        toast.success('Teacher added successfully!');
      }
      setModalOpen(false);
      fetchTeachers();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to save teacher');
    }
  };

  const handleDelete = async (id, name) => {
    if (!window.confirm(`Are you sure you want to delete ${name}?`)) return;
    try {
      await api.delete(`/teachers/${id}`);
      toast.success('Teacher deleted');
      fetchTeachers();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to delete');
    }
  };

  const exportToExcel = () => {
    const data = teachers.map((t) => ({
      'Employee ID': t.employeeId,
      'Name': t.name,
